  out(<A, B>);
  // m2: S -> A : senc( (B, Kab, T, Ticket), Ksa )
  in(xencS);
  let < =B, Kab, T, Ticket > = sdec(xencS, Ksa) in   // equality check on B as specified
  // Security-relevant events
  event Secret(A, B, Kab);
  event CommitA(A, B, Kab, T);
  // m3: A -> B : Ticket  (opaque: senc( (Kab, A, T), Ksb ))
  out(Ticket)


let Responder(B, Ksb) =
  event StartB(B);
  // m3: A -> B : Ticket
  in(Ticket);
  let < Kab, A_from_ticket, T > = sdec(Ticket, Ksb) in
  // Security-relevant events
  event Secret(A_from_ticket, B, Kab);
  event CommitB(A_from_ticket, B, Kab, T)


let Server() =
  event StartS();
  // Receive request
  in(req);
  let <A, B> = req in
  // Look up registered long-term symmetric keys for A and B
  lookup ltk(A, Ksa) in
  lookup ltk(B, Ksb) in
  // Fresh session key and timestamp
  new Kab;
  new T;
  // Construct ticket and payload
  let Ticket  = senc(<Kab, A, T>, Ksb) in
  let Payload = <B, Kab, T, Ticket> in
  // Security-relevant events before sending
  event RunningS(A, B, Kab, T);
  event Secret(A, B, Kab);
  // Send response
  out(senc(Payload, Ksa))


/* Key-compromise helper: upon trigger "('reveal', X)" outputs long-term key of X */
let RevealHelper(X, Ksx) =
  in(< 'reveal', X >);
  event Reveal(X);
  out(Ksx)


