     ==>
       (Ex #j. RunningS(A, B, K, T) @ #j & #j < #i)
       | (Ex #r. Reveal(A) @ #r & #r < #i)
       | (Ex #r. Reveal(B) @ #r & #r < #i)
  "


// 4) Injective agreement (B authenticates S)
lemma injective_agree_B:
  "All A B K T #i.
     CommitB(A, B, K, T) @ #i
     ==>
       (
         Ex #j.
           RunningS(A, B, K, T) @ #j
           & #j < #i
           & (All #j2. RunningS(A, B, K, T) @ #j2 ==> #j2 = #j)
           & (All #i2. CommitB(A, B, K, T) @ #i2 ==> #i2 = #i)
       )
       | (Ex #r. Reveal(A) @ #r & #r < #i)
       | (Ex #r. Reveal(B) @ #r & #r < #i)
  "


